        attribute(name = "controlUnits", type = "List<ControlUnit>")
        attribute(name = "sensors", type = "List<Sensor>")
    }
    val controlUnit = classOf(name = "ControlUnit") {
        attribute(name = "functions", type = "List<DrivingFunction>")
    }
    val drivingFunction = classOf(name = "DrivingFunction") {
        attribute(name = "name", type = "String")
    }
    val sensor = classOf(name = "Sensor") {
        isAbstract = true
        attribute(name = "serialNumber", type = "String", isReadOnly = true)
        attribute(name = "samplingRate", type = "Double")
        operation(name = "calibrate") { returns(typeName = "Boolean") }
    }
    val camera = classOf(name = "Camera") { extends(general = sensor) }
    val radar = classOf(name = "Radar") { extends(general = sensor) }
    val lidar = classOf(name = "Lidar") { extends(general = sensor) }
    val measurement = classOf(name = "Measurement") {
        attribute(name = "timestamp", type = "DateTime")
    }
    val testCase = classOf(name = "TestCase") {
        attribute(name = "scenario", type = "TestScenario")
        attribute(name = "function", type = "DrivingFunction")
    }
    val testScenario = classOf(name = "TestScenario") {
        attribute(name = "description", type = "String")
    }
    val testRun = classOf(name = "TestRun") {
        attribute(name = "vehicle", type = "Vehicle")
        attribute(name = "testCase", type = "TestCase")
        attribute(name = "measurements", type = "List<Measurement>")
        attribute(name = "result", type = "TestResult")
    }
    val testResult = classOf(name = "TestResult") {
        attribute(name = "status", type = "String")
    }
    association(source = drivingFunction, target = sensor) {
        source { multiplicity(spec = "1..*") }
        target { multiplicity(spec = "1..*"); role = "sensors" }
    }
    association(source = sensor, target = measurement) {
        source { multiplicity(spec = "1") }
        target { multiplicity(spec = "0..*"); role = "measurements" }
    }
}

@startuml
abstract class Payment {
  amount
  date
}
class MembershipFeePayment {
  contributionYear
}
class Donation {
  earmarkedCampaign
}
class Member {
  status
}
class MembershipApplication {
  applicationStatus
}
class DistrictChapter
class StateChapter
class Committee
class Mandate {
  termOfOffice
}
class Campaign
class Deployment {
  hours
}
interface NotificationContract

Payment <|-- MembershipFeePayment
Payment <|-- Donation
Member "1" o-- "0..*" Payment : payments
DistrictChapter "1" o-- "0..*" Member : members
DistrictChapter "1" o-- "0..*" MembershipApplication : applications
DistrictChapter "1" o-- "0..*" Campaign : campaigns
StateChapter "1" o-- "0..*" DistrictChapter : districtChapters
Committee "1" o-- "0..*" Mandate : mandates
Mandate "1" *-- "1" Member : awardedTo
Campaign "1" o-- "0..*" Deployment : deployments
Deployment "1" *-- "1" Member : participant
Member "1" <|.. NotificationContract
@enduml

classDiagram(name = "MembershipManagementSystem") {
    val stateChapter = classOf(name = "StateChapter")
    val districtChapter = classOf(name = "DistrictChapter")
    val member = classOf(name = "Member") {
        attribute(name = "status", type = "String")
    }
    val membershipApplication = classOf(name = "MembershipApplication") {
        attribute(name = "applicationStatus", type = "String")
    }
    val notificationContract = classOf(name = "NotificationContract")
    val committee = classOf(name = "Committee")
    val mandate = classOf(name = "Mandate") {
        attribute(name = "termOfOffice", type = "String")
    }
    val campaign = classOf(name = "Campaign")
    val deployment = classOf(name = "Deployment") {
        attribute(name = "hours", type = "Int")
    }
    val payment = classOf(name = "Payment") {
        isAbstract = true
        attribute(name = "amount", type = "Double")
        attribute(name = "date", type = "Date")
    }
    val membershipFeePayment = classOf(name = "MembershipFeePayment") {
        extends(general = payment)
        attribute(name = "contributionYear", type = "Int")
    }
    val donation = classOf(name = "Donation") {
        extends(general = payment)
        attribute(name = "earmarkedCampaign", type = campaign, multiplicity = Multiplicity(lower = "0", upper = "1"))
    }

    association(source = stateChapter, target = districtChapter) {
        aggregation = AggregationKind.COMPOSITE
        source { multiplicity(lower = "1", upper = "1") }
        target { multiplicity(lower = "0", upper = "*"); role = "districts" }
    }
    association(source = districtChapter, target = member) {
        aggregation = AggregationKind.COMPOSITE
        source { multiplicity(lower = "1", upper = "1") }
        target { multiplicity(lower = "0", upper = "*"); role = "members" }
    }
    association(source = districtChapter, target = membershipApplication) {
        aggregation = AggregationKind.COMPOSITE
        source { multiplicity(lower = "1", upper = "1") }
        target { multiplicity(lower = "0", upper = "*"); role = "applications" }
    }
    association(source = membershipApplication, target = member) {
        source { multiplicity(lower = "1", upper = "1") }
        target { multiplicity(lower = "0", upper = "1"); role = "emergesAs" }
    }
    association(source = member, target = notificationContract) {
        source { multiplicity(lower = "1", upper = "1") }
        target { multiplicity(lower = "1", upper = "1"); role = "contact" }
    }
    association(source = committee, target = mandate) {
        aggregation = AggregationKind.COMPOSITE
        source { multiplicity(lower = "1", upper = "1") }
        target { multiplicity(lower = "0", upper = "*"); role = "mandates" }
    }
    association(source = mandate, target = member) {
        source { multiplicity(lower = "1", upper = "1") }
        target { multiplicity(lower = "1", upper = "1"); role = "holder" }
    }
    association(source = districtChapter, target = campaign) {
        aggregation = AggregationKind.COMPOSITE
        source { multiplicity(lower = "1", upper = "1") }
        target { multiplicity(lower = "0", upper = "*"); role = "campaigns" }
    }
    association(source = campaign, target = deployment) {
        aggregation = AggregationKind.COMPOSITE
        source { multiplicity(lower = "1", upper = "1") }
        target { multiplicity(lower = "0", upper = "*"); role = "deployments" }
    }
    association(source = deployment, target = member) {
        source { multiplicity(lower = "1", upper = "1") }
        target { multiplicity(lower = "1", upper = "1"); role = "participant" }
    }
    association(source = member, target = payment) {
        aggregation = AggregationKind.COMPOSITE
        source { multiplicity(lower = "1", upper = "1") }
        target { multiplicity(lower = "0", upper = "*"); role = "payments" }
    }
}

