import dev.kuml.sysml2.dsl.sysml2Model

sysml2Model(name = "ADASModel") {
    val sensor = partDef(name = "Sensor")
    val camera = partDef(name = "Camera") {
        generalization(general = sensor)
    }
    val radar = partDef(name = "Radar") {
        generalization(general = sensor)
    }
    val lidar = partDef(name = "Lidar") {
        generalization(general = sensor)
    }
    val sensorSuite = partDef(name = "SensorSuite") {
        part(name = "camera", typeId = camera.id)
        part(name = "radar", typeId = radar.id)
        part(name = "lidar", typeId = lidar.id)
    }
    val fusionUnit = partDef(name = "FusionUnit") {
        part(name = "sensorSuite", typeId = sensorSuite.id)
    }
    val driverAssistanceControlUnit = partDef(name = "DriverAssistanceControlUnit") {
        part(name = "fusionUnit", typeId = fusionUnit.id)
    }
    val adasSubsystem = partDef(name = "ADASSubsystem") {
        part(name = "driverAssistanceControlUnit", typeId = driverAssistanceControlUnit.id)
    }
    bdd(name = "ADASModel BDD") {
        include(sensor)
        include(camera)
        include(radar)
        include(lidar)
        include(sensorSuite)
        include(fusionUnit)
        include(driverAssistanceControlUnit)
        include(adasSubsystem)
    }
}
